// Computed data for episode detail pages generated by episode.njk pagination.
// Sets per-episode title, description, and OG image used in base.njk <head>.

module.exports = {
  eleventyComputed: {
    title: (data) => {
      const ep = data.episode;
      if (!ep) return 'Checkin to Checkout';
      return `${ep.title} | Checkin to Checkout`;
    },
    description: (data) => {
      const ep = data.episode;
      if (!ep) return '';
      return ep.plainDescription || ep.title;
    },
    og_image: (data) => {
      const ep = data.episode;
      return ep && ep.image ? ep.image : 'https://mobile1st.com/img/og-default.png';
    },
  },
};
